// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/login", wrapper.Login)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/logout", wrapper.Logout)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/oauth/exchange", wrapper.ExchangeOAuth)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/oauth/start", wrapper.StartOAuth)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/auth/status", wrapper.GetAuthStatus)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/config", wrapper.GetConfig)
	})
	r.Group(func(r chi.Router) {
		r.Patch(options.BaseURL+"/config", wrapper.PatchConfig)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/config/reset", wrapper.ResetConfig)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/config/restart", wrapper.RestartConfig)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/config/schema", wrapper.GetConfigSchema)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/downloads", wrapper.ClearDownloads)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/downloads", wrapper.ListDownloads)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/downloads", wrapper.SubmitDownload)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/downloads/{id}", wrapper.RemoveDownload)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/downloads/{id}", wrapper.GetDownload)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/downloads/{id}/cancel", wrapper.CancelDownload)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/events", wrapper.GetEvents)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/health", wrapper.GetHealth)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/illusts/following", wrapper.ListFollowingIllusts)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/illusts/ranking", wrapper.ListRanking)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/illusts/recommended", wrapper.ListRecommended)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/illusts/{id}", wrapper.GetIllust)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/illusts/{id}/bookmark", wrapper.DeleteBookmark)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/illusts/{id}/bookmark", wrapper.GetBookmarkDetail)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/illusts/{id}/bookmark", wrapper.AddBookmark)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/illusts/{id}/ugoira", wrapper.GetUgoiraMetadata)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/search/illusts", wrapper.SearchIllusts)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/search/users", wrapper.SearchUsers)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/users/{id}", wrapper.GetUser)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/users/{id}/bookmarks", wrapper.ListUserBookmarks)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/users/{id}/follow", wrapper.DeleteFollow)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/users/{id}/follow", wrapper.AddFollow)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/users/{id}/following", wrapper.ListUserFollowing)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/users/{id}/illusts", wrapper.ListUserIllusts)
	})

	return r
}

